@module trackerPage  src=trackerPage.lua  loc=1272  sha=952e5a2
@deps util, timing

# Invariants & contracts (module)
  @map:invariant  page is render + input only; tracker state lives in vm/ec/tm — never cached here
  @map:invariant  cm/vm read fresh each frame; only ephemeral UI state persists across frames (gridX/Y, dragging, modalState, picker*, laneConsumed)
  @map:invariant  col.x == nil is the visibility predicate; every per-column draw must gate on it
  @map:invariant  cell coordinates are 0-indexed; header rows at -HEADER, row-number gutter at -GUTTER
  @map:invariant  writes go through vm or cmgr commands — page never reaches into tm

# Module-level constants
  @const ImGui = require 'imgui' '0.10'  @ 20

# Module-level functions (private)
  @fn print(...)  @ 12

@factory newTrackerPage(cm, cmgr, chrome, gui)  @ 23
  @map:contract  owns and constructs the tracker substack (mm/tm/vm/seqMgr) — coord hands it primitives, never the substack; the take arrives later via tp:bind from the coordinator's poll loop
  @map:invariant  lane strip renders only cc/pb/at columns; other types show as tinted background

  # Shapes
    @shape  ToolbarSegment = { id, render = fn(), visible? = fn() -> bool }
    @shape  modalState = { title, prompt, callback, buf, kind?='confirm'|'takeProps', nameBuf?, rowsBuf?, rowsGen?, mode?, refocusRows? }
    @shape  focusState = { suppressKbd:bool, acceptCmds:bool }

  # Private state
    @state mm = newMidiManager(nil)  @ 24
    @state tm = newTrackerManager(mm, cm)  @ 25
    @state vm = newTrackerView(tm, cm, cmgr)  @ 26
    @state seqMgr = newSequenceManager(tm, vm, cm)  @ 27
    @state GUTTER = 4  @ 31   -- in grid chars
    @state HEADER = 3  @ 32   -- in grid rows
    @state gridX = nil  @ 34
    @state gridY = nil  @ 35
    @state gridOriginX = 0  @ 36
    @state gridOriginY = 0  @ 37
    @state gridWidth = 0  @ 38
    @state gridHeight = 0  @ 39
    @state dragging = false  @ 64   -- tracker-grid selection drag: click → held → release
    @state modalState = nil  @ 65
    @state swingEditor = newSwingEditor(vm, cm, chrome, ctx, seqMgr)  @ 66
    @state curveEd = newCurveEditor(ctx)  @ 67
    @state laneConsumed = false  @ 68
    @state toolbar  @ 69   -- lazy: chrome may be nil at construction in tests
    @state renderFns = {  @ 134

  # Private functions
    @fn layoutColumns(cols, scrollCol)  @ 44
        @map:contract  clears col.x on every col before assigning; off-screen cols end the frame with col.x == nil
    @fn renderNote(evt, col, row)  @ 73
    @fn noteName(pitch)  @ 74
    @fn renderPB(evt)  @ 122
    @fn renderCC(evt)  @ 129
    @fn renderCell(evt, col, row)  @ 143
    @fn printer(ctx, gX, gY, x0, y0)  @ 150
    @fn drawTextAt(xpos, ypos, txt, c)  @ 157
    @fn laneStripRows()  @ 206
        @map:contract  returns 0 when laneStrip.visible is false — both layout and draw branch on this
    @fn libPickerItems(current, lib, presets, excludePresets)  @ 212   -- Off=group 1, saved lib=group 2, unseeded preset (+ prefix)=group 3.
    @fn pickTemper(name)  @ 234   -- Seed lib if absent before committing to slot.
    @fn pickSwing(name)  @ 241
    @fn pickColSwing(chan, name)  @ 248
    @fn drawSampleDropdown()  @ 261   -- Hex stays visible when unassigned so `<`/`>` advertise their step. No "Off" row — every sl
    @fn drawTrackerToolbarBits()  @ 372
    @fn computeLayout(budgetW, budgetH)  @ 379
        @map:contract  must run before any draw routine that reads chanX/chanW/chanOrder/totalWidth/gridHeight
        @map:contract  calls vm:setGridSize(gridWidth, gridHeight) so vm scroll math sees the live viewport
    @fn drawLaneStrip()  @ 406
        @map:contract  publishes laneConsumed=true if the curve editor claimed input this frame; handleMouse short-circuits on it
    @fn rowToX(row)  @ 421
    @fn drawTracker()  @ 521
        @map:contract  assumes computeLayout ran this frame; reads chanX/chanW/chanOrder/totalWidth and gridOriginX/Y
    @fn drawStatusBar()  @ 725
    @fn nearestStop(mouseX, mouseY)  @ 828
        @map:contract  returns (col, stop, fracX) or (nil, nil, fracX); fracX kept separate so callers distinguish "past last col" from "inside col N"
    @fn handleMouse()  @ 848
        @map:contract  returns immediately if laneConsumed is set; lane strip wins gestures over the tracker grid
        @map:contract  right-click on channel-label row toggles mute; click on label rows selects channel/column; body click moves cursor and arms drag
    @fn handleKeys(kr)  @ 956   -- Page-internal raw input. commandHeld gates a held command key from leaking into the char q
        @map:contract  no-op when modalState or chrome.pickerIsActive() is set, or when any ImGui item is active (focused InputText etc.)
        @map:contract  drains the entire input-queue per frame; reads ec/grid fresh each iteration since editEvent may rebuild
    @fn drawModal()  @ 1004
        @map:contract  callback runs under pcall; an exception is logged to the REAPER console and does not abort the frame
    @fn close(invoke, ...)  @ 1019
    @fn scaleBy(factor)  @ 1047   -- Mutating rowsBuf externally is invisible to an active InputText, which caches its own buff
    @fn pressedAny(specs)  @ 1054
    @fn openPrompt(title, prompt, callback)  @ 1118
    @fn openConfirm(title, callback, prompt)  @ 1123
    @fn scopedAction(title, base)  @ 1136   -- Naming convention <base>Selection / <base>All is the contract.
        @map:contract  requires vm to expose both `<base>Selection` and `<base>All` methods

  # Public API
    -- Cell renderers
    -- Drawing
    @api pt:text(x, y, txt, c, font)  @ 164
    @api pt:textCentred(x1, x2, y, txt, c)  @ 174
    @api pt:textCentredSmall(x1, x2, y, txt, size, c)  @ 181
